import { describe, expect, it } from '@a0n/gnosis/test';
import { runTopologicalXorSkipBenchmark } from './topological-xor-skip-benchmark';

describe('gnosis topological XOR skip benchmark', () => {
  it('reports skip planning throughput and retention buckets', () => {
    const report = runTopologicalXorSkipBenchmark({
      candidates: 40,
      iterations: 2,
      retentionBudget: 5,
    });

    expect(report.label).toBe('gnosis-topological-xor-skip-benchmark-v1');
    expect(report.skipTargets).toBe(25);
    expect(report.retainedSkipTargets).toBe(5);
    expect(report.recomputableSkipTargets).toBe(20);
    expect(report.measureTargets).toBe(5);
    expect(report.reconstructTargets).toBe(10);
    expect(report.skipRatePerthou).toBe(625);
    expect(report.decisionsPerSecond).toBeGreaterThan(0);
  });
});
